import{_ as s,c as a,o as l,aN as p}from"./chunks/framework.DXgs1r1w.js";const u=JSON.parse('{"title":"Linux 接收与发送网络包的流程","description":"","frontmatter":{"date":"2024-09-01T10:00:00.000Z","title":"Linux 接收与发送网络包的流程","outline":"deep","lastUpdated":true,"footer":true,"permalink":"/pages/a1c3e8","categories":["Linux","计算机网络"]},"headers":[],"relativePath":"Linux/计算机网络/Linux 接收与发送网络包的流程.md","filePath":"Linux/计算机网络/Linux 接收与发送网络包的流程.md","lastUpdated":1784100320000}'),e={name:"Linux/计算机网络/Linux 接收与发送网络包的流程.md"};function i(r,n,t,o,c,d){return l(),a("div",null,[...n[0]||(n[0]=[p(`<h1 id="linux-接收与发送网络包的流程" tabindex="-1">Linux 接收与发送网络包的流程 <a class="header-anchor" href="#linux-接收与发送网络包的流程" aria-label="Permalink to &quot;Linux 接收与发送网络包的流程&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>在 Linux 系统中，网络包的收发都要经过<strong>内核协议栈</strong>的处理。一次网络 I/O 并不是用户进程直接操作网卡，而是分为两层：</p><ul><li><strong>用户态</strong>：应用程序通过 <code>socket</code> 系统调用与内核交互。</li><li><strong>内核态</strong>：内核协议栈（TCP/IP 协议族）完成分片、封装、路由、校验，并最终交给网卡驱动收发数据。</li></ul><p>整个流程涉及的核心层次（对应 TCP/IP 四层模型）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  应用层 (Application)   用户态               │</span></span>
<span class="line"><span>│  HTTP / FTP / DNS ...   socket 读写          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  传输层 (Transport)    内核态               │</span></span>
<span class="line"><span>│  TCP / UDP             分段 / 端口复用        │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  网络层 (Network)                            │</span></span>
<span class="line"><span>│  IP                     路由 / 分片 / 寻址     │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  链路层 (Link)                               │</span></span>
<span class="line"><span>│  网卡驱动 / 协议栈                          │</span></span>
<span class="line"><span>│  封装 MAC / 软中断 / NAPI                    │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  物理层 (Physical)                          │</span></span>
<span class="line"><span>│  网卡 (NIC)             DMA / 中断            │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>发送与接收的关键区别在于：<strong>发送是用户进程主动触发（上半部在进程上下文）</strong>，<strong>接收是由网卡中断被动触发（上半部在中断上下文，实际处理在软中断）</strong>。</p><hr><h2 id="一、linux-发送网络包的流程" tabindex="-1">一、Linux 发送网络包的流程 <a class="header-anchor" href="#一、linux-发送网络包的流程" aria-label="Permalink to &quot;一、Linux 发送网络包的流程&quot;">​</a></h2><p>发送流程从用户进程调用 <code>write()</code> / <code>send()</code> 开始，数据自上而下穿过协议栈，最终由网卡发出。</p><h3 id="整体流程图" tabindex="-1">整体流程图 <a class="header-anchor" href="#整体流程图" aria-label="Permalink to &quot;整体流程图&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户进程 (用户态)</span></span>
<span class="line"><span>   │  send() / write()</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>socket 层 (sock_sendmsg)</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>TCP / UDP 层 (传输层)</span></span>
<span class="line"><span>   │  - TCP: 复制数据到内核缓冲区, 按 MSS 分段, 添加 TCP 头</span></span>
<span class="line"><span>   │  - UDP: 直接封装 UDP 头 (不缓冲)</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>IP 层 (网络层)</span></span>
<span class="line"><span>   │  - 添加 IP 头 (源/目的 IP, TTL, 校验和)</span></span>
<span class="line"><span>   │  - 路由查找 (确定出口设备和下一跳)</span></span>
<span class="line"><span>   │  - 必要时 IP 分片</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>邻居子系统 / ARP</span></span>
<span class="line"><span>   │  - 解析下一跳 MAC 地址</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>网卡驱动 (链路层)</span></span>
<span class="line"><span>   │  - 添加以太网帧头 (源/目的 MAC)</span></span>
<span class="line"><span>   │  - 封装 FCS 校验</span></span>
<span class="line"><span>   │  - 通过 DMA 把 skb 放入网卡发送环形队列 (TX Ring)</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>网卡 (NIC 硬件)</span></span>
<span class="line"><span>   │  - 从 TX Ring 取出数据</span></span>
<span class="line"><span>   │  - 转换成电信号/光信号发出</span></span>
<span class="line"><span>   │  - 发送完成后触发中断通知 CPU</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>            物理网络线路</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br></div></div><h3 id="关键步骤说明" tabindex="-1">关键步骤说明 <a class="header-anchor" href="#关键步骤说明" aria-label="Permalink to &quot;关键步骤说明&quot;">​</a></h3><ol><li><p><strong>系统调用</strong>：用户进程调用 <code>send()</code> / <code>sendto()</code> / <code>write()</code>，陷入内核执行 <code>sock_sendmsg()</code>。</p></li><li><p><strong>传输层处理（TCP 为例）</strong>：</p><ul><li>数据从用户缓冲区<strong>拷贝</strong>到内核的 <code>sk_buff</code>（简称 <code>skb</code>，是 Linux 网络的核心数据结构）。</li><li>TCP 根据 <strong>MSS（最大报文段长度）</strong> 对数据进行分段。</li><li>为每个分段添加 TCP 头部（源/目的端口、序号、窗口大小、校验和）。</li><li>数据放入发送缓冲区，等待发送（受滑动窗口和拥塞窗口控制）。</li></ul></li><li><p><strong>网络层处理（IP 层）</strong>：</p><ul><li>为数据包添加 IP 头部（源 IP、目的 IP、TTL、协议类型、IP 校验和）。</li><li>进行<strong>路由查找</strong>，确定从哪个网卡发出、下一跳是谁。</li><li>若数据包超过 MTU 且不允许分片，则进行 <strong>IP 分片</strong>。</li></ul></li><li><p><strong>邻居子系统（ARP）</strong>：</p><ul><li>查找下一跳 IP 对应的 MAC 地址（在 ARP 缓存中）。</li><li>若未命中，先发送 ARP 请求，缓存到后再继续。</li></ul></li><li><p><strong>链路层 / 网卡驱动</strong>：</p><ul><li>封装以太网帧头（源 MAC、目的 MAC、类型字段）和帧尾 FCS。</li><li>通过 <strong>DMA</strong> 将 <code>skb</code> 写入网卡发送环形队列（TX Ring Buffer）。</li><li>通知网卡有数据待发送。</li></ul></li><li><p><strong>网卡发送</strong>：</p><ul><li>网卡 DMA 读取 TX Ring 中的数据。</li><li>转换成比特流发送到物理线路。</li><li>发送完成后通过 <strong>MSI/MSI-X 中断</strong>通知 CPU，内核释放 <code>skb</code>。</li></ul></li></ol><hr><h2 id="二、linux-接收网络包的流程" tabindex="-1">二、Linux 接收网络包的流程 <a class="header-anchor" href="#二、linux-接收网络包的流程" aria-label="Permalink to &quot;二、Linux 接收网络包的流程&quot;">​</a></h2><p>接收流程由网卡硬件被动触发，是「中断 → 软中断 → 协议栈逐层上传」的过程。</p><h3 id="整体流程图-1" tabindex="-1">整体流程图 <a class="header-anchor" href="#整体流程图-1" aria-label="Permalink to &quot;整体流程图&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>物理网络线路</span></span>
<span class="line"><span>   │  网卡收到数据帧</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>网卡 (NIC 硬件)</span></span>
<span class="line"><span>   │  - DMA 将帧写入内存接收环形队列 (RX Ring)</span></span>
<span class="line"><span>   │  - 触发硬中断 (IRQ)</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>硬中断处理 (上半部, 中断上下文)</span></span>
<span class="line"><span>   │  - 仅做最小处理: 关闭网卡中断</span></span>
<span class="line"><span>   │  - 触发软中断 (NET_RX_SOFTIRQ)</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>软中断处理 (下半部, 进程上下文 ksoftirqd)</span></span>
<span class="line"><span>   │  - NAPI 轮询 (poll) 网卡</span></span>
<span class="line"><span>   │  - 从 RX Ring 取出数据, 构造 skb</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>网卡驱动</span></span>
<span class="line"><span>   │  - 去除以太网帧头, 校验 FCS</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>IP 层 (网络层)</span></span>
<span class="line"><span>   │  - 校验 IP 头, 去 IP 头</span></span>
<span class="line"><span>   │  - 路由判断: 本机 / 转发</span></span>
<span class="line"><span>   │  - IP 分片重组 (如有)</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>TCP / UDP 层 (传输层)</span></span>
<span class="line"><span>   │  - 根据端口查找 socket</span></span>
<span class="line"><span>   │  - TCP: 校验序号, 去重, 排序, 放入接收缓冲区, 发 ACK</span></span>
<span class="line"><span>   │  - UDP: 直接放入接收队列</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>socket 层</span></span>
<span class="line"><span>   │  - 数据放入 socket 接收缓冲区</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>用户进程 (用户态)</span></span>
<span class="line"><span>   │  recv() / read() 系统调用取走数据</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>        应用程序处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br></div></div><h3 id="关键步骤说明-1" tabindex="-1">关键步骤说明 <a class="header-anchor" href="#关键步骤说明-1" aria-label="Permalink to &quot;关键步骤说明&quot;">​</a></h3><ol><li><p><strong>网卡接收</strong>：网卡收到数据帧后，通过 <strong>DMA</strong> 直接写入内核预先分配的内存（RX Ring Buffer），避免 CPU 逐字节拷贝。</p></li><li><p><strong>硬中断（上半部，Top Half）</strong>：</p><ul><li>网卡触发 <strong>IRQ 硬中断</strong>，CPU 暂停当前任务转入中断处理程序。</li><li>硬中断<strong>只做最少量工作</strong>：通知网卡停止产生中断（防止风暴），然后<strong>触发软中断</strong> <code>NET_RX_SOFTIRQ</code>，立即返回。</li><li>这样设计是为了让硬中断尽量短，不长时间阻塞 CPU。</li></ul></li><li><p><strong>软中断（下半部，Bottom Half）</strong>：</p><ul><li>内核在稍后（中断返回时或 <code>ksoftirqd</code> 内核线程）执行软中断。</li><li>通过 <strong>NAPI（New API）</strong> 机制<strong>轮询</strong>网卡，批量从 RX Ring 取走数据帧，构造成 <code>skb</code>。</li><li>NAPI 结合了<strong>中断</strong>和<strong>轮询</strong>的优点：有数据时触发中断，随后轮询清空队列，避免高流量下中断风暴。</li></ul></li><li><p><strong>链路层</strong>：驱动去除以太网帧头，校验 FCS，将纯净的 IP 包交给上层。</p></li><li><p><strong>网络层（IP 层）</strong>：</p><ul><li>校验 IP 头、检查 TTL。</li><li>根据目的 IP 做<strong>路由决策</strong>：本机接收 / 需要转发。</li><li>若是分片包，进行 <strong>IP 分片重组</strong>。</li></ul></li><li><p><strong>传输层（TCP/UDP）</strong>：</p><ul><li>根据目的端口查找对应的 <code>socket</code>。</li><li><strong>TCP</strong>：校验序号、去重、按序放入接收缓冲区，并发送 ACK 确认；若数据按序到达则通知应用层。</li><li><strong>UDP</strong>：直接放入接收队列，不保证顺序和可靠。</li></ul></li><li><p><strong>socket 层 → 用户进程</strong>：</p><ul><li>数据放入 socket 的<strong>接收缓冲区</strong>。</li><li>用户进程调用 <code>recv()</code> / <code>read()</code> 时，内核将数据从内核缓冲区<strong>拷贝</strong>到用户缓冲区。</li></ul></li></ol><hr><h2 id="三、核心机制详解" tabindex="-1">三、核心机制详解 <a class="header-anchor" href="#三、核心机制详解" aria-label="Permalink to &quot;三、核心机制详解&quot;">​</a></h2><h3 id="_1-硬中断-vs-软中断" tabindex="-1">1. 硬中断 vs 软中断 <a class="header-anchor" href="#_1-硬中断-vs-软中断" aria-label="Permalink to &quot;1. 硬中断 vs 软中断&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>硬中断 (Top Half)</th><th>软中断 (Bottom Half)</th></tr></thead><tbody><tr><td>触发方式</td><td>硬件（如网卡 IRQ）</td><td>内核代码主动触发</td></tr><tr><td>执行上下文</td><td>中断上下文（不能睡眠）</td><td>可视为进程上下文（ksoftirqd）</td></tr><tr><td>执行时间</td><td>极短</td><td>相对较长</td></tr><tr><td>主要职责</td><td>通知、调度</td><td>实际的数据包处理</td></tr><tr><td>例子</td><td>网卡收到包触发 IRQ</td><td>NET_RX_SOFTIRQ 处理 skb</td></tr></tbody></table><h3 id="_2-napi-机制" tabindex="-1">2. NAPI 机制 <a class="header-anchor" href="#_2-napi-机制" aria-label="Permalink to &quot;2. NAPI 机制&quot;">​</a></h3><p>传统方式每个包都触发一次中断，高流量下 CPU 被中断淹没。NAPI 改进为：</p><ul><li>网卡收到包 → 触发一次硬中断 → 关闭中断 → 进入轮询模式。</li><li>软中断中 <code>poll()</code> 循环从 RX Ring 取包，直到取空或达到配额（如 <code>netdev_budget</code>）。</li><li>取空后重新开启网卡中断。</li><li>在低流量时退化为纯中断模式，兼顾延迟和吞吐。</li></ul><h3 id="_3-sk-buff-skb" tabindex="-1">3. sk_buff（skb） <a class="header-anchor" href="#_3-sk-buff-skb" aria-label="Permalink to &quot;3. sk_buff（skb）&quot;">​</a></h3><p><code>sk_buff</code> 是 Linux 网络子系统的核心数据结构，贯穿收发全程：</p><ul><li>通过**数据指针（head/data/tail/truesize）**实现零拷贝式的头部添加/剥离。</li><li>发送时逐层「往后推」指针添加头部；接收时逐层「往前推」指针剥离头部。</li><li>避免了每层都进行数据搬移，提高性能。</li></ul><h3 id="_4-dma-与环形队列-ring-buffer" tabindex="-1">4. DMA 与环形队列（Ring Buffer） <a class="header-anchor" href="#_4-dma-与环形队列-ring-buffer" aria-label="Permalink to &quot;4. DMA 与环形队列（Ring Buffer）&quot;">​</a></h3><ul><li>网卡与内核通过**环形队列（Ring Buffer）**交换数据，队列描述符指向真实数据内存。</li><li>接收时网卡 <strong>DMA 直写</strong>内存，发送时内核 <strong>DMA 直读</strong>内存，CPU 无需参与搬移。</li><li>若 Ring Buffer 满（CPU 处理不过来），包会被丢弃，表现为 <code>ifconfig</code> 中的 <code>RX dropped</code> 增加。</li></ul><hr><h2 id="四、性能优化相关技术" tabindex="-1">四、性能优化相关技术 <a class="header-anchor" href="#四、性能优化相关技术" aria-label="Permalink to &quot;四、性能优化相关技术&quot;">​</a></h2><h3 id="_1-多队列与-rss" tabindex="-1">1. 多队列与 RSS <a class="header-anchor" href="#_1-多队列与-rss" aria-label="Permalink to &quot;1. 多队列与 RSS&quot;">​</a></h3><p>现代网卡支持<strong>多队列（Multi-Queue）</strong>，配合 <strong>RSS（Receive Side Scaling）</strong> 用哈希将不同流分发到不同队列，再绑定到不同 CPU 核心，实现接收侧的并行处理，避免单核瓶颈。</p><h3 id="_2-零拷贝-zero-copy" tabindex="-1">2. 零拷贝（Zero-Copy） <a class="header-anchor" href="#_2-零拷贝-zero-copy" aria-label="Permalink to &quot;2. 零拷贝（Zero-Copy）&quot;">​</a></h3><p>常规收发数据需要在「内核缓冲区」和「用户缓冲区」之间拷贝。零拷贝技术（如 <code>sendfile</code>、<code>splice</code>、<code>mmap</code>）减少甚至消除拷贝：</p><ul><li><code>sendfile</code>：文件数据直接从内核页缓存经 socket 发出，无需进入用户态。</li><li>大文件传输、代理服务器场景下显著提升吞吐、降低 CPU 占用。</li></ul><h3 id="_3-大页与-tso-gro" tabindex="-1">3. 大页与 TSO/GRO <a class="header-anchor" href="#_3-大页与-tso-gro" aria-label="Permalink to &quot;3. 大页与 TSO/GRO&quot;">​</a></h3><ul><li><strong>TSO（TCP Segmentation Offload）</strong>：由网卡代替 CPU 做 TCP 分段，减轻 CPU 负担。</li><li><strong>GRO（Generic Receive Offload）</strong>：接收侧将多个小包聚合后再交给协议栈，减少软中断次数。</li><li><strong>LRO / UFO</strong> 等类似卸载技术，把协议栈工作下放到网卡硬件。</li></ul><h3 id="_4-中断亲和性-irq-affinity" tabindex="-1">4. 中断亲和性（IRQ Affinity） <a class="header-anchor" href="#_4-中断亲和性-irq-affinity" aria-label="Permalink to &quot;4. 中断亲和性（IRQ Affinity）&quot;">​</a></h3><p>通过 <code>/proc/irq/&lt;irq&gt;/smp_affinity</code> 把网卡中断绑定到指定 CPU，配合 RSS 做到网卡队列与 CPU 一一对应，减少缓存失效和上下文切换。</p><hr><h2 id="五、收发流程对比总结" tabindex="-1">五、收发流程对比总结 <a class="header-anchor" href="#五、收发流程对比总结" aria-label="Permalink to &quot;五、收发流程对比总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>发送流程</th><th>接收流程</th></tr></thead><tbody><tr><td>触发方</td><td>用户进程主动（系统调用）</td><td>网卡被动（硬件中断）</td></tr><tr><td>上半部</td><td>进程上下文（send 系统调用）</td><td>中断上下文（硬中断 Top Half）</td></tr><tr><td>下半部</td><td>由 TCP 拥塞/窗口调度发送</td><td>软中断（NET_RX_SOFTIRQ / NAPI）</td></tr><tr><td>数据方向</td><td>用户态 → 内核 → 网卡 → 线路</td><td>线路 → 网卡 → 内核 → 用户态</td></tr><tr><td>关键结构</td><td>sk_buff、发送缓冲区</td><td>sk_buff、RX Ring、接收缓冲区</td></tr><tr><td>典型瓶颈</td><td>CPU 拷贝、锁竞争</td><td>软中断单核压力、Ring 溢出丢包</td></tr></tbody></table><blockquote><p>一句话记忆：<strong>发送是「自上而下的封装」，接收是「自下而上的解包」；发送靠进程驱动，接收靠中断+软中断驱动。</strong></p></blockquote>`,48)])])}const h=s(e,[["render",i]]);export{u as __pageData,h as default};
